// Content Concept Generator
// Picks today's pillar, style, animal, and builds a creative prompt

const calendar = {
  pillars: [
    { id: 'old_masters', name: 'Old Masters, New Paws', prompts: [
      'Reimagine "{painting}" by {artist} but with a {animal} as the subject',
      'A {animal} posed exactly like the subject in "{painting}" by {artist}',
    ]},
    { id: 'cinema', name: 'Cinema Unleashed', prompts: [
      'A {animal} recreating the iconic {movie} movie poster',
      'Movie poster parody of {movie} starring a {animal}',
    ]},
    { id: 'daily_portrait', name: 'The Daily Portrait', prompts: [
      'A stunning artistic portrait of a {animal} in {setting}',
      'Majestic {animal} portrait with dramatic lighting',
    ]},
    { id: 'fantasy', name: 'What Breed Is This?', prompts: [
      'A mythical hybrid creature: half {animal}, half {creature2}, in a {setting}',
      'A {animal} with magical {feature} in a fantasy landscape',
    ]},
    { id: 'historical', name: 'Pets Through Time', prompts: [
      'A {animal} dressed as a {historical_figure} in {era} era',
      'A {animal} in {era} period clothing and setting',
    ]},
    { id: 'tiny_worlds', name: 'Tiny Worlds', prompts: [
      'A {animal} running a tiny {shop_type} in a miniature world',
      'A {animal} in a whimsical diorama-like {scene}',
    ]},
  ],
  styles: [
    'Renaissance Oil Painting', 'Studio Ghibli / Anime', 'Cyberpunk Neon',
    'Watercolor Botanical', 'Pop Art (Warhol/Lichtenstein)', 'Pixel Art / 8-Bit',
    'Art Nouveau', 'Hyperrealism', 'Ukiyo-e (Japanese Woodblock)', 'Dark Fantasy / Gothic'
  ],
  animals: [
    'duck', 'cat', 'dog', 'owl', 'fox', 'lion', 'wolf', 'elephant',
    'hummingbird', 'pug', 'corgi', 'shiba inu', 'persian cat', 'parrot',
    'hamster', 'frog', 'mouse', 'hedgehog', 'snow leopard', 'turtle',
    'dalmatian', 'golden retriever', 'bulldog', 'barn owl', 'eagle',
    'penguin', 'flamingo', 'raccoon', 'red panda', 'otter'
  ],
  paintings: [
    { title: 'Girl with a Pearl Earring', artist: 'Vermeer' },
    { title: 'The Birth of Venus', artist: 'Botticelli' },
    { title: 'American Gothic', artist: 'Grant Wood' },
    { title: 'The Starry Night', artist: 'Van Gogh' },
    { title: 'Mona Lisa', artist: 'da Vinci' },
    { title: 'The Scream', artist: 'Munch' },
    { title: 'The Great Wave', artist: 'Hokusai' },
  ],
  movies: [
    'The Matrix', 'Jaws', 'Titanic', 'Scarface', 'Star Wars',
    'The Godfather', 'Jurassic Park', 'Pulp Fiction', 'Forrest Gump',
    'The Shining', 'E.T.', 'Back to the Future'
  ],
  eras: [
    { era: 'Ancient Egyptian', figure: 'pharaoh' },
    { era: 'Medieval', figure: 'knight' },
    { era: 'Renaissance', figure: 'nobleman' },
    { era: 'Feudal Japanese', figure: 'samurai' },
    { era: '1920s Art Deco', figure: 'jazz singer' },
    { era: 'Victorian', figure: 'detective' },
    { era: '1960s Space Age', figure: 'astronaut' },
  ],
  shops: ['ramen shop', 'bakery', 'bookshop', 'flower shop', 'coffee cart', 'tailor'],
  scenes: ['mushroom forest library', 'treehouse village', 'cloud city', 'underwater coral palace'],
  features: ['butterfly wings', 'crystalline antlers', 'bioluminescent fur', 'flower crown that blooms'],
  creatures: ['phoenix', 'dragon', 'unicorn', 'griffin'],
  settings: ['moonlit forest', 'golden hour savanna', 'misty mountain peak', 'rainy Tokyo street', 'cherry blossom garden']
};

const pick = (arr) => arr[Math.floor(Math.random() * arr.length)];
const dayOfWeek = new Date().getDay(); // 0=Sun, 1=Mon, ...

// Map day to pillar
const pillarMap = [0, 2, 3, 5, 1, 2, 4]; // Sun=old_masters, Mon=portrait, Tue=fantasy, Wed=tiny, Thu=cinema, Fri=portrait, Sat=historical
const pillar = calendar.pillars[pillarMap[dayOfWeek]];
const style = pick(calendar.styles);
const animal = pick(calendar.animals);

// Build the prompt template
let promptTemplate = pick(pillar.prompts);
let prompt = promptTemplate
  .replace('{animal}', animal)
  .replace('{painting}', pick(calendar.paintings).title)
  .replace('{artist}', pick(calendar.paintings).artist)
  .replace('{movie}', pick(calendar.movies))
  .replace('{era}', pick(calendar.eras).era)
  .replace('{historical_figure}', pick(calendar.eras).figure)
  .replace('{shop_type}', pick(calendar.shops))
  .replace('{scene}', pick(calendar.scenes))
  .replace('{feature}', pick(calendar.features))
  .replace('{creature2}', pick(calendar.creatures))
  .replace('{setting}', pick(calendar.settings));

const fullPrompt = `Create an artistic image in ${style} style: ${prompt}. The image should be stunning, high quality, suitable for an Instagram post. Square format (1:1 ratio, 1080x1080 or larger). Make it visually striking and shareable.`;

const today = new Date().toISOString().split('T')[0];

return [{
  json: {
    date: today,
    pillar: pillar.name,
    style: style,
    animal: animal,
    concept: prompt,
    manus_prompt: fullPrompt,
    attempt: 1,
    max_attempts: 3
  }
}];

