// Extract the image URL and file info from Manus output
const output = $input.first().json.output || [];
let imageUrl = null;
let imageFileName = null;
let assistantMessage = '';

for (const item of output) {
  if (item.content) {
    for (const content of item.content) {
      if (content.type === 'output_file') {
        imageUrl = content.fileUrl;
        imageFileName = content.fileName;
      }
      if (content.type === 'output_text' && item.role === 'assistant') {
        assistantMessage = content.text;
      }
    }
  }
}

// Get concept info from earlier in the chain
const concept = $('Generate Concept').item.json;

return [{
  json: {
    ...concept,
    image_url: imageUrl,
    image_filename: imageFileName,
    manus_task_id: $input.first().json.id,
    manus_share_url: $input.first().json.metadata?.share_url,
    manus_response: assistantMessage,
    credit_usage: $input.first().json.credit_usage
  }
}];

